class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class WordDictionary:
    def __init__(self):
        self.root = TrieNode()

    def addWord(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word: str) -> bool:
        return self._search_recursive(self.root, word, 0)

    def _search_recursive(self, node: TrieNode, word: str, index: int) -> bool:
        if index == len(word):
            return node.is_end_of_word

        char = word[index]

        if char == '.':
            for child_char in node.children:
                if self._search_recursive(node.children[child_char], word, index + 1):
                    return True
            return False
        else:
            if char in node.children:
                return self._search_recursive(node.children[char], word, index + 1)
            else:
                return False
